   236|  <style>
   237|    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
   238|
   239|    :root {
   240|      --gold: #FFD700;
   241|      --gold-light: #FFF2A3;
   242|      --gold-dim: rgba(255,215,0,0.1);
   243|      --gold-border: rgba(255,215,0,0.22);
   244|      --bg: #000000;
   245|      --bg2: #141414;
   246|      --surface: #1A1A1A;
   247|      --surface2: #242424;
   248|      --border: #2A2A2A;
   249|      --text: #FFFFFF;
   250|      --text2: #909090;
   251|      --text3: #555555;
   252|      --green: #00C48C;
   253|      --red: #FF4D4D;
   254|      --blue: #4A90D9;
