   256|
   257|    html { scroll-behavior: auto; overflow-x: hidden; width: 100%; -webkit-text-size-adjust: 100%; text-size-adjust: 100%; }
   258|
   259|    body {
   260|      font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
   261|      background: var(--bg);
   262|      color: var(--text);
   263|      overflow-x: hidden;
   264|      -webkit-font-smoothing: antialiased;
   265|      width: 100%;
   266|      max-width: 100vw;
   267|      /* overscroll-behavior-y: none; REMOVED — it blocked pull-to-refresh and made scroll-up feel stuck on mobile */
   268|    }
   269|
   270|    /* ─── LAYOUT-SHIFT DEFENSE (CLS) ─── */
   271|    img, video, picture { max-width: 100%; display: block; }
   272|    .media-frame { width: 100%; aspect-ratio: 16 / 10; overflow: hidden; position: relative; background: #111; }
   273|    .media-frame img, .media-frame video { width: 100%; height: 100%; object-fit: cover; display: block; }
   274|    .ivx-skeleton {
   275|      position: absolute; inset: 0;
   276|      background: linear-gradient(90deg, #141414 0%, #1f1f1f 50%, #141414 100%);
   277|      background-size: 200% 100%;
   278|      animation: ivxSkel 1.4s ease-in-out infinite;
   279|      z-index: 1; pointer-events: none;
   280|    }
   281|    .ivx-skeleton.ivx-skel-hide { display: none; }
   282|    @keyframes ivxSkel { 0% { background-position: 200% 0; } 100% { background-position: -200% 0; } }
   283|
   284|    /* ─── REELS CARDS (reserved space — no intrinsic-size jump) ─── */
   285|    #vx-grid { display: grid; gap: 18px; grid-template-columns: 1fr; contain: layout style; }
   286|    @media (min-width: 640px) { #vx-grid { grid-template-columns: repeat(2, 1fr); } }
   287|    .vx-card { background: var(--surface); border: 1px solid var(--border); border-radius: 18px; overflow: hidden; contain: layout style; }
   288|    .vx-media { position: relative; width: 100%; aspect-ratio: 9 / 16; max-height: 78vh; background: #000; overflow: hidden; }
   289|    .vx-media video { width: 100%; height: 100%; object-fit: cover; display: block; background: #000; }
   290|    .vx-play-overlay, .vx-heart-burst, .vx-mute-btn { z-index: 6; }
   291|    .vx-head, .vx-actions, .vx-likes-line, .vx-caption, .vx-viewall, .vx-comments, .vx-time, .vx-comment-form { contain: content; }
   292|
   293|    /* ─── NAV ─── */
   294|    nav {
   295|      position: fixed;
   296|      top: 0; left: 0; right: 0;
   297|      z-index: 200;
   298|      display: flex;
   299|      align-items: center;
   300|      justify-content: space-between;
   301|      padding: 0 40px;
   302|      height: 68px;
   303|      background: rgba(10,10,10,0.88);
   304|      backdrop-filter: blur(24px);
   305|      -webkit-backdrop-filter: blur(24px);
   306|      border-bottom: 1px solid var(--border);
   307|      transition: background 0.3s;
   308|    }
   309|    .nav-logo {
   310|      display: flex; align-items: center; gap: 10px;
   311|      text-decoration: none;
   312|    }
   313|    .nav-logo-icon {
   314|      width: 40px; height: 40px;
   315|      flex-shrink: 0;
   316|      display: flex; align-items: center; justify-content: center;
   317|      border-radius: 10px;
   318|      overflow: hidden;
   319|    }
   320|    .nav-logo-icon img {
   321|      width: 40px; height: 40px;
   322|      object-fit: contain;
   323|      display: block;
   324|    }
   325|    .nav-logo-name {
   326|      font-size: 14px; font-weight: 800;
   327|      letter-spacing: 1.8px; color: var(--text);
   328|    }
   329|    .nav-links {
   330|      display: flex; align-items: center; gap: 32px; list-style: none;
   331|    }
   332|    .nav-links a {
   333|      color: var(--text2); text-decoration: none;
   334|      font-size: 13.5px; font-weight: 500;
   335|      transition: color 0.2s;
   336|    }
   337|    .nav-links a:hover { color: var(--text); }
   338|    .nav-cta-btn {
   339|      background: var(--gold) !important;
   340|      color: #000 !important;
   341|      font-weight: 700 !important;
   342|      padding: 9px 20px;
   343|      border-radius: 10px;
   344|      transition: background 0.2s, transform 0.15s !important;
   345|    }
   346|    .nav-cta-btn:hover { background: var(--gold-light) !important; transform: translateY(-1px); }
   347|    .nav-hamburger {
   348|      display: none; cursor: pointer; flex-direction: column; gap: 5px; padding: 4px;
   349|      position: relative;
   350|      z-index: 260;
   351|      touch-action: manipulation;
   352|      -webkit-tap-highlight-color: transparent;
   353|    }
   354|    .live-deal-actions button {
